sql:
SELECT users.email, credits_calculation.total_credits
FROM users
JOIN credits_calculation ON users.user_id = credits_calculation.user_id;

SELECT ec.user_id, COUNT(DISTINCT ec.rate_class_id) AS different_rate_classes_count
FROM energy_consumption ec
GROUP BY ec.user_id;

SELECT username
FROM users
WHERE user_id NOT IN (SELECT user_id FROM energy_consumption);

SELECT rate_class_id, AVG(peak_credit) AS average_peak_credit
FROM generation_credits
GROUP BY rate_class_id;

SELECT peak_credits 
FROM credits_calculation
WHERE user_id = (SELECT user_id FROM users WHERE email = 'john.doe@utilitycompany.com');

SELECT rate_class_id, rate_class_name, peak_rate, off_peak_rate
FROM rate_classes
WHERE peak_rate > 0.15 AND off_peak_rate < 0.10;

SELECT rate_class_id, rate_class_name, description, peak_rate
FROM rate_classes
WHERE rate_class_id = 1;

SELECT COUNT(compliance_id) 
FROM regulatory_compliance 
WHERE regulatory_body = 'California Public Utilities Commission';

SELECT AVG(peak_credit) AS average_peak_credit, AVG(off_peak_credit) AS average_off_peak_credit
FROM generation_credits
WHERE rate_class_id = 0;
